import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    static class Item {
        long w, v;
        double r;
        Item(long w, long v) {
            this.w = w;
            this.v = v;
            this.r = (double) v / (double) w;
        }
    }
    public static void main(String[] args) throws Exception {
        // Read entire input as a raw string (may contain literal "\\n" sequences)
        String raw = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Convert escaped newlines to real newlines
        raw = raw.replace("\\n", "\n");
        // Use a Scanner on the processed string for easy tokenization
        Scanner sc = new Scanner(new StringReader(raw));
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long Wmax = sc.nextLong();
            Item[] items = new Item[N];
            for (int i = 0; i < N; i++) {
                long w = sc.nextLong();
                long v = sc.nextLong();
                items[i] = new Item(w, v);
            }
            Arrays.sort(items, (a, b) -> Double.compare(b.r, a.r));
            double total = 0.0;
            long remaining = Wmax;
            for (Item it : items) {
                if (it.w <= remaining) {
                    total += it.v;
                    remaining -= it.w;
                } else {
                    total += it.v * ((double) remaining / (double) it.w);
                    break;
                }
            }
            sb.append(String.format(Locale.US, "%.2f", total)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

